#!/usr/bin/env python3
import hashlib
import itertools

TARGET = "a60458d2180258d47d7f7bef5236b33e86711ac926518ca4545ebf24cdc0b76c".lower()

base_tokens = [
    'md2','md4','md5','sha1','sha224','sha256','sha384','sha512',
    'sha3_224','sha3_256','sha3_384','sha3_512',
    'blake2b','blake2s',
    'ripemd128','ripemd160','ripemd256','ripemd320',
    'whirlpool','tiger','gost','streebog','sm3','crc32'
]


def variants(tok: str):
    out = set([tok])
    # separators variants
    out.add(tok.replace('_', '-'))
    out.add(tok.replace('-', '_'))
    out.add(tok.replace('_', ''))
    out.add(tok.replace('-', ''))
    # if contains sha3 family, generate collapsed forms and alt sep
    low = tok.lower()
    if low.startswith('sha3'):
        for mid in ['_', '-', '']:
            for suf in ['224', '256', '384', '512']:
                out.add(f'sha3{mid}{suf}')
                out.add(f'SHA3{mid}{suf}')
    # case variants
    for x in list(out):
        out.add(x.lower())
        out.add(x.upper())
    return out


cands = set()
for t in base_tokens:
    cands |= variants(t)

# Include hashlib available algorithm names and normalized forms
for a in hashlib.algorithms_available:
    cands.add(a)
    cands.add(a.lower())
    cands.add(a.upper())
    cands.add(a.replace('_', '-'))
    cands.add(a.replace('-', '_'))
    cands.add(a.replace('_', ''))
    cands.add(a.replace('-', ''))

# clean empties
cands = {c for c in cands if c}


def outer_hash(algo: str, data: bytes):
    if algo == 'sha256':
        return hashlib.sha256(data).hexdigest()
    if algo == 'sha3_256':
        return hashlib.sha3_256(data).hexdigest()
    if algo == 'blake2s32':
        return hashlib.blake2s(data, digest_size=32).hexdigest()
    if algo == 'sm3':
        h = hashlib.new('sm3')
        h.update(data)
        return h.hexdigest()
    if algo == 'sha512_256':
        h = hashlib.new('sha512_256')
        h.update(data)
        return h.hexdigest()
    raise ValueError(algo)

transforms = {
    'raw': lambda s: s,
    'stripped': lambda s: s.strip(),
    'trailing_newline': lambda s: s + '\n',
    'prefix_hash:': lambda s: 'hash:' + s,
    'suffix_:hash': lambda s: s + ':hash',
    'prefix_algo:': lambda s: 'algo:' + s,
    'suffix_:algo': lambda s: s + ':algo',
}

outers = ['sha256', 'sha3_256', 'blake2s32', 'sm3', 'sha512_256']

# Filter unavailable outers gracefully
available_outers = []
for o in outers:
    try:
        _ = outer_hash(o, b'test')
        available_outers.append(o)
    except Exception:
        pass

print(f"[+] target={TARGET}")
print(f"[+] candidates={len(cands)}")
print(f"[+] transforms={len(transforms)}")
print(f"[+] outer algos={available_outers}")

checked = 0
matches = []
for cand in sorted(cands):
    for tname, tf in transforms.items():
        msg = tf(cand).encode()
        for outer in available_outers:
            checked += 1
            d = outer_hash(outer, msg)
            if d == TARGET:
                matches.append((outer, cand, tname, tf(cand)))
                print("[MATCH]", outer, cand, tname, repr(tf(cand)))

print(f"[+] checked={checked}")
if not matches:
    print("[-] no exact match")
else:
    print(f"[+] total matches={len(matches)}")
    for m in matches:
        print("    ", m)

#!/usr/bin/env python3
import hashlib, itertools, subprocess
TARGET='a60458d2180258d47d7f7bef5236b33e86711ac926518ca4545ebf24cdc0b76c'

bases = [
    'crackme','crack_me','crack-me','crack me','crypto','hash','hashes','salt','algorithm',
    'sha256','sha-256','sha2','sha3','sha3-256','blake2s','sm3','ripemd128','md5','sha1',
    'ctf','flag','password','admin','letmein','welcome','qwerty','dragon','secret','challenge',
    'can_you_crack_this','canyoucrackthis','crackthis','encrypt','encryption','method','digest'
]

prefixes=['','flag','ctf','the','my','super','ultra']
suffixes=['','1','12','123','1234','!','?','2024','2025','_ctf','-ctf','_hash','-hash']
seps=['','_','-','.']

cands=set()
for b in bases:
    cands.add(b)
    cands.add(b.lower())
    cands.add(b.upper())
    cands.add(b.title())

for p,b,s in itertools.product(prefixes,bases,suffixes):
    cands.add(f"{p}{b}{s}")
    cands.add(f"{p}_{b}{s}")

for a,b,s in itertools.product(bases,bases,suffixes):
    if a==b: continue
    for sep in seps:
        cands.add(f"{a}{sep}{b}{s}")

cands |= {w[::-1] for w in list(cands)[:15000]}

cands = [w for w in cands if 1 <= len(w) <= 64]
print(f"[*] candidates: {len(cands)}")

algos = ['sha256','sha3_256','blake2s']
for w in cands:
    b=w.encode()
    for a in algos:
        h=getattr(hashlib,a)(b).hexdigest()
        if h==TARGET:
            print(f"[+] FOUND {a}: {w}")
            raise SystemExit(0)

# try SM3 via openssl if present
try:
    subprocess.run(['openssl','list','-digest-algorithms'], stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
    for i,w in enumerate(cands):
        p=subprocess.run(['openssl','dgst','-sm3'],input=w.encode(),stdout=subprocess.PIPE,stderr=subprocess.DEVNULL)
        out=p.stdout.decode(errors='ignore').strip().lower()
        # format: SM3(stdin)= <hash>
        if '=' in out:
            h=out.split('=')[-1].strip()
            if h==TARGET:
                print(f"[+] FOUND sm3: {w}")
                raise SystemExit(0)
        if i and i%5000==0:
            pass
except Exception:
    pass

print('[-] no match')

